#!/usr/bin/env bash
# Build distributed-inference as a NAPI-compatible Node.js native module.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

OUT_DIR="$SCRIPT_DIR/dist"
mkdir -p "$OUT_DIR"

echo "[build-napi] cargo build --release --lib --features napi"
cargo build --release --lib --features napi

UNAME="$(uname -s)"
case "$UNAME" in
  Darwin)
    SRC="target/release/libdistributed_inference.dylib"
    ;;
  Linux)
    SRC="target/release/libdistributed_inference.so"
    ;;
  MINGW*|MSYS*|CYGWIN*)
    SRC="target/release/distributed_inference.dll"
    ;;
  *)
    echo "[build-napi] unsupported platform: $UNAME" >&2
    exit 1
    ;;
esac

if [[ ! -f "$SRC" ]]; then
  echo "[build-napi] expected artifact missing: $SRC" >&2
  exit 1
fi

DST="$OUT_DIR/distributed_inference.node"
cp "$SRC" "$DST"

SIZE="$(wc -c < "$DST" | tr -d ' ')"
echo "[build-napi] wrote $DST (${SIZE} bytes)"
